<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<meta name="viewport" content="width=device-width, initial-scale=1.0">
<title>AC Paint Center – Inventory System</title>
<link href="https://fonts.googleapis.com/css2?family=Bebas+Neue&family=Barlow:wght@300;400;500;600;700&display=swap" rel="stylesheet">
<style>
  *, *::before, *::after { box-sizing: border-box; margin: 0; padding: 0; }

  :root {
    --red: #D01212;
    --red-dark: #A50F0F;
    --red-light: #FDEAEA;
    --black: #111111;
    --gray-dark: #333333;
    --gray-mid: #666666;
    --gray-light: #F4F4F4;
    --white: #FFFFFF;
    --border: #E2E2E2;
    --shadow: rgba(0,0,0,0.08);
  }

  body {
    background: var(--white);
    font-family: 'Barlow', sans-serif;
    min-height: 100vh;
    display: flex;
    align-items: stretch;
  }

  /* Left panel */
  .side-panel {
    flex: 1;
    background: var(--white);
    display: flex;
    align-items: center;
    justify-content: center;
    position: relative;
    overflow: hidden;
  }

  /* Diagonal red stripe at bottom */
  .side-panel::before {
    content: '';
    position: absolute;
    bottom: -60px;
    left: -60px;
    width: 500px;
    height: 500px;
    background: var(--red-light);
    border-radius: 50%;
    z-index: 0;
  }

  /* Top-right accent */
  .side-panel::after {
    content: '';
    position: absolute;
    top: -40px;
    right: -40px;
    width: 220px;
    height: 220px;
    background: rgba(208,18,18,0.06);
    border-radius: 50%;
    z-index: 0;
  }

  /* Diagonal stripe pattern */
  .stripe-bg {
    position: absolute;
    inset: 0;
    background: repeating-linear-gradient(
      -55deg,
      transparent,
      transparent 30px,
      rgba(208,18,18,0.03) 30px,
      rgba(208,18,18,0.03) 31px
    );
    z-index: 0;
  }

  .side-content {
    position: relative;
    z-index: 1;
    text-align: center;
    padding: 3rem;
  }

  .side-logo {
    width: 300px;
    animation: fadeInDown 0.7s ease both;
    filter: drop-shadow(0 8px 24px rgba(0,0,0,0.12));
  }

  .side-tagline {
    margin-top: 1.8rem;
    font-family: 'Bebas Neue', sans-serif;
    font-size: 1rem;
    letter-spacing: 0.3em;
    color: var(--gray-mid);
    animation: fadeInUp 0.7s 0.2s ease both;
  }

  .side-divider {
    width: 50px;
    height: 3px;
    background: var(--red);
    margin: 1rem auto 0;
    animation: expandW 0.5s 0.45s ease both;
    transform-origin: center;
    border-radius: 2px;
  }

  /* Right panel */
  .login-panel {
    width: 460px;
    background: var(--white);
    display: flex;
    align-items: center;
    justify-content: center;
    padding: 3rem 2.5rem;
    border-left: 1px solid var(--border);
    box-shadow: -6px 0 32px rgba(0,0,0,0.05);
    position: relative;
  }

  /* Red top bar */
  .login-panel::before {
    content: '';
    position: absolute;
    top: 0; left: 0; right: 0;
    height: 4px;
    background: var(--red);
  }

  .login-box {
    width: 100%;
    animation: fadeInRight 0.6s 0.1s ease both;
  }

  .login-header {
    margin-bottom: 2.2rem;
  }

  .eyebrow {
    font-size: 0.7rem;
    letter-spacing: 0.22em;
    color: var(--red);
    text-transform: uppercase;
    font-weight: 600;
    margin-bottom: 0.4rem;
  }

  .login-header h1 {
    font-family: 'Bebas Neue', sans-serif;
    font-size: 2.4rem;
    letter-spacing: 0.05em;
    color: var(--black);
    line-height: 1;
  }

  .login-header p {
    margin-top: 0.5rem;
    font-size: 0.87rem;
    color: var(--gray-mid);
    font-weight: 300;
  }

  /* Fields */
  .field { margin-bottom: 1.1rem; }

  .field label {
    display: block;
    font-size: 0.75rem;
    font-weight: 600;
    letter-spacing: 0.07em;
    text-transform: uppercase;
    color: var(--gray-dark);
    margin-bottom: 0.45rem;
  }

  .input-wrap { position: relative; }

  .input-wrap .icon {
    position: absolute;
    left: 13px;
    top: 50%;
    transform: translateY(-50%);
    width: 16px;
    height: 16px;
    opacity: 0.35;
  }

  .input-wrap input {
    width: 100%;
    background: var(--gray-light);
    border: 1.5px solid var(--border);
    border-radius: 8px;
    padding: 0.78rem 1rem 0.78rem 2.65rem;
    color: var(--black);
    font-family: 'Barlow', sans-serif;
    font-size: 0.95rem;
    transition: border-color 0.2s, background 0.2s, box-shadow 0.2s;
    outline: none;
  }

  .input-wrap input::placeholder { color: #BBBBBB; }

  .input-wrap input:focus {
    border-color: var(--red);
    background: var(--white);
    box-shadow: 0 0 0 3px rgba(208,18,18,0.1);
  }

  .toggle-pw {
    position: absolute;
    right: 13px;
    top: 50%;
    transform: translateY(-50%);
    background: none;
    border: none;
    cursor: pointer;
    opacity: 0.3;
    padding: 0;
    transition: opacity 0.2s;
  }
  .toggle-pw:hover { opacity: 0.65; }

  /* Row */
  .row {
    display: flex;
    justify-content: space-between;
    align-items: center;
    margin: 0.8rem 0 1.6rem;
  }

  .remember {
    display: flex;
    align-items: center;
    gap: 7px;
    cursor: pointer;
    font-size: 0.83rem;
    color: var(--gray-mid);
    user-select: none;
  }

  .remember input[type="checkbox"] {
    width: 15px;
    height: 15px;
    accent-color: var(--red);
    cursor: pointer;
  }

  .forgot {
    font-size: 0.83rem;
    color: var(--red);
    text-decoration: none;
    font-weight: 500;
    transition: opacity 0.2s;
  }
  .forgot:hover { opacity: 0.7; }

  /* Button */
  .btn-login {
    width: 100%;
    padding: 0.9rem;
    background: var(--red);
    color: #fff;
    border: none;
    border-radius: 8px;
    font-family: 'Bebas Neue', sans-serif;
    font-size: 1.15rem;
    letter-spacing: 0.15em;
    cursor: pointer;
    transition: background 0.18s, transform 0.1s, box-shadow 0.2s;
    box-shadow: 0 4px 18px rgba(208,18,18,0.25);
  }

  .btn-login:hover {
    background: var(--red-dark);
    box-shadow: 0 6px 24px rgba(208,18,18,0.35);
  }
  .btn-login:active { transform: scale(0.98); }

  /* Divider */
  .or-divider {
    display: flex;
    align-items: center;
    gap: 12px;
    margin: 1.4rem 0 0;
  }
  .or-divider span { flex: 1; height: 1px; background: var(--border); }
  .or-divider p { font-size: 0.75rem; color: #AAAAAA; white-space: nowrap; }

  /* Footer */
  .footer-note {
    margin-top: 1.8rem;
    text-align: center;
    font-size: 0.74rem;
    color: #AAAAAA;
    line-height: 1.7;
    border-top: 1px solid var(--border);
    padding-top: 1.2rem;
  }

  .footer-note strong { color: var(--red); }

  /* Animations */
  @keyframes fadeInDown {
    from { opacity: 0; transform: translateY(-18px); }
    to   { opacity: 1; transform: translateY(0); }
  }
  @keyframes fadeInUp {
    from { opacity: 0; transform: translateY(10px); }
    to   { opacity: 1; transform: translateY(0); }
  }
  @keyframes fadeInRight {
    from { opacity: 0; transform: translateX(16px); }
    to   { opacity: 1; transform: translateX(0); }
  }
  @keyframes expandW {
    from { transform: scaleX(0); }
    to   { transform: scaleX(1); }
  }

  @media (max-width: 768px) {
    body { flex-direction: column; }
    .side-panel { min-height: 240px; flex: none; }
    .side-logo { width: 200px; }
    .login-panel { width: 100%; border-left: none; border-top: 1px solid var(--border); box-shadow: 0 -4px 20px rgba(0,0,0,0.05); }
  }
</style>
</head>
<body>

<!-- Left panel -->
<div class="side-panel">
  <div class="stripe-bg"></div>
  <div class="side-content">
    <img class="side-logo" src="data:image/png;base64," alt="AC Paint Center">
    <div class="side-divider"></div>
    <p class="side-tagline">Inventory Management System</p>
  </div>
</div>

<!-- Right login panel -->
<div class="login-panel">
  <div class="login-box">

    <div class="login-header">
      <p class="eyebrow">Welcome back</p>
      <h1>Sign In</h1>
      <p>Access your AC Paint Center inventory dashboard</p>
    </div>

    <div class="field">
      <label for="username">Username</label>
      <div class="input-wrap">
        <svg class="icon" viewBox="0 0 24 24" fill="none" stroke="#333" stroke-width="2" stroke-linecap="round" stroke-linejoin="round">
          <path d="M20 21v-2a4 4 0 0 0-4-4H8a4 4 0 0 0-4 4v2"/>
          <circle cx="12" cy="7" r="4"/>
        </svg>
        <input type="text" id="username" placeholder="Enter your username" autocomplete="username">
      </div>
    </div>

    <div class="field">
      <label for="password">Password</label>
      <div class="input-wrap">
        <svg class="icon" viewBox="0 0 24 24" fill="none" stroke="#333" stroke-width="2" stroke-linecap="round" stroke-linejoin="round">
          <rect x="3" y="11" width="18" height="11" rx="2" ry="2"/>
          <path d="M7 11V7a5 5 0 0 1 10 0v4"/>
        </svg>
        <input type="password" id="password" placeholder="Enter your password" autocomplete="current-password">
        <button class="toggle-pw" type="button" onclick="togglePw()" title="Show/hide password">
          <svg id="eye-icon" width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="#333" stroke-width="2" stroke-linecap="round" stroke-linejoin="round">
            <path d="M1 12s4-8 11-8 11 8 11 8-4 8-11 8-11-8-11-8z"/>
            <circle cx="12" cy="12" r="3"/>
          </svg>
        </button>
      </div>
    </div>

    <div class="row">
      <label class="remember">
        <input type="checkbox" id="remember">
        Remember me
      </label>
      <a href="#" class="forgot">Forgot password?</a>
    </div>

 <form method="POST" action="/login" id="login-form">
    @csrf
    <input type="hidden" name="username" id="hidden-username">
    <input type="hidden" name="password" id="hidden-password">
    <input type="hidden" name="remember" id="hidden-remember">
    <button class="btn-login" type="button" onclick="handleLogin()">Sign In</button>
</form>

    <div class="footer-note">
      <strong>AC Paint Center</strong> &copy; 2025<br>
      Inventory Management System v1.0
    </div>
  </div>
</div>

<script>
  function togglePw() {
    const pw = document.getElementById('password');
    const icon = document.getElementById('eye-icon');
    if (pw.type === 'password') {
      pw.type = 'text';
      icon.innerHTML = '<path d="M17.94 17.94A10.07 10.07 0 0 1 12 20c-7 0-11-8-11-8a18.45 18.45 0 0 1 5.06-5.94M9.9 4.24A9.12 9.12 0 0 1 12 4c7 0 11 8 11 8a18.5 18.5 0 0 1-2.16 3.19m-6.72-1.07a3 3 0 1 1-4.24-4.24"/><line x1="1" y1="1" x2="23" y2="23"/>';
    } else {
      pw.type = 'password';
      icon.innerHTML = '<path d="M1 12s4-8 11-8 11 8 11 8-4 8-11 8-11-8-11-8z"/><circle cx="12" cy="12" r="3"/>';
    }
  }
function handleLogin() {
    const u = document.getElementById('username').value.trim();
    const p = document.getElementById('password').value;
    const r = document.getElementById('remember').checked;

    if (!u || !p) { shake(); return; }

    document.getElementById('hidden-username').value = u;
    document.getElementById('hidden-password').value = p;
    document.getElementById('hidden-remember').value = r ? '1' : '0';

    const btn = document.querySelector('.btn-login');
    btn.textContent = 'Signing in...';
    btn.disabled = true;

    document.getElementById('login-form').submit();
}

  function shake() {
    const box = document.querySelector('.login-box');
    box.style.animation = 'none';
    box.offsetHeight;
    box.style.animation = 'shake 0.4s ease';
  }

  document.addEventListener('keydown', e => { if (e.key === 'Enter') handleLogin(); });

  const s = document.createElement('style');
  s.textContent = '@keyframes shake{0%,100%{transform:translateX(0)}20%,60%{transform:translateX(-7px)}40%,80%{transform:translateX(7px)}}';
  document.head.appendChild(s);
</script>
</body>
</html>